counter = 0

for file in filelist:
    counter += 1
    ofile = os.path.basename(file)
    if os.path.exists(ofile):
      # print(f"{ofile} already exists — skipping")
      continue
    parts = ofile.split(".")
    time_range = parts[9]
    if time_range not in ["20350101-20441231", "20450101-20541231"]:
        # print(f"{ofile} is not from 2015 or 2035 or 2045 — skipping")
        continue

    sys.stdout.write("File Nr " + str(counter) + " downloading " + ofile + " ... ")
    sys.stdout.flush()
    infile = opener.open(file)
    outfile = open(ofile, "wb")
    outfile.write(infile.read())
    outfile.close()
    sys.stdout.write("done\n")